    justifyContent: "center",
    gap: 8,
    padding: "40px 0"
  },
  emptyIcon: {
    fontSize: 36
  },
  chartCenter: {
    position: "absolute",
    top: "50%",
    left: "50%",
    transform: "translate(-50%, -50%)",
    textAlign: "center",
    pointerEvents: "none",
    marginTop: -18
  },
