  topoSub: {
    fontSize: 11,
    color: "var(--text-muted)"
  },
  dockerBadge: {
    fontSize: 11,
    fontWeight: 700,
    marginBottom: 4
  },
  podChip: {
    padding: "3px 10px",
    borderRadius: 100,
    fontSize: 11,
    fontWeight: 600,
    marginTop: 4
  },
  forkRow: {
    display: "flex",
    gap: 80,
    alignItems: "flex-start"
  },
  forkBranch: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center"
  },
  forkLine: {
    display: "none"
